      comparisonTable: { title: 'Common Section Properties', headers: ['Section', 'I', 'Z', 'Use'], rows: [['Rectangle', 'bd3/12', 'bd2/6', 'simple beams'], ['Solid circle', 'pi d4/64', 'pi d3/32', 'round bars'], ['Hollow circle', 'pi(D4-d4)/64', 'I/(D/2)', 'pipes and shafts'], ['I-section', 'built-up calculation', 'large for weight', 'girders']] },
