      labSheet: { experimentName: 'Bending Stress Study by Beam Deflection Apparatus', aim: 'To observe bending behaviour of a simply supported beam under load.', apparatus: ['beam test rig', 'loads', 'dial gauge', 'scale'], theory: 'Bending stress is proportional to bending moment and distance from neutral axis under elastic bending.', procedure: ['Place beam on supports.', 'Apply central load.', 'Measure deflection.', 'Increase load gradually.', 'Calculate bending moment.', 'Discuss stress distribution.'], observationTable: { headers: ['Load', 'Span', 'BM', 'Deflection', 'Remark'], rows: 5 }, precautions: ['Do not exceed elastic load.', 'Place load at marked position.', 'Zero dial gauge.', 'Avoid shock loading.'], result: 'Beam deflection and bending effect increase with applied load within elastic range.' },
