      labSheet: { experimentName: 'Study of Shear Stress Distribution Models', aim: 'To compare shear stress distribution in rectangular, circular and I-sections.', apparatus: ['section models', 'graph sheet', 'calculator'], theory: 'Shear stress distribution depends on first moment of area above or below the layer.', procedure: ['Sketch each section.', 'Mark neutral axis.', 'Calculate average shear.', 'Apply maximum shear factor.', 'Draw distribution shape.', 'Compare locations of maximum stress.'], observationTable: { headers: ['Section', 'Area', 'V', 'tau avg', 'tau max', 'Location'], rows: 4 }, precautions: ['Use consistent units.', 'Mark neutral axis correctly.', 'Do not mix bending and shear distributions.', 'Label diagrams neatly.'], result: 'Shear stress is maximum near neutral axis for common sections and zero at free surfaces.' },
